import React from 'react'
import ReactDOM from 'react-dom'
import '../src/index.css'
import { createFFmpeg, fetchFile } from '@ffmpeg/ffmpeg';
const ffmpeg = createFFmpeg({log: true})
const loading = (
    <div>
        <h3 id = "loading">Loading...</h3>
    </div>
)
ReactDOM.render(loading, document.getElementById('root'))
console.log("Initializing ffmpeg")
initffmpeg()
async function initffmpeg(){
    await ffmpeg.load()
    console.log("Loaded")
    const page = (
        <div>
            <h2 id = "title">Screen Recorder</h2>
            <br></br>
            <button id = "start" onClick = {init}>Start</button>
            <br></br>
            <button id = "stop">Stop</button>
            <div id = "output">
                <h1>Output</h1>
                <br></br>
                <video id = "outputvid"></video>
            </div>
        </div>
    )
    ReactDOM.render(page, document.getElementById('root'))
    async function init(){
        document.getElementById('start').disabled = true
        document.getElementById('stop').disabled = false
        document.getElementById('stop').onclick = function(){
            recorder.stop()
            document.getElementById('stop').disabled = true
            document.getElementById('start').disabled = false
        }
        const stream = await navigator.mediaDevices.getDisplayMedia({
            video: {mediaSource: "screen"}
        })
        const recorder = new MediaRecorder(stream, {mimeType: 'video/webm; codecs=vp9'})
        const screenchunks = []
        recorder.ondataavaliable = e => screenchunks.push(e.data)
        recorder.start()
        recorder.onstop = e => {
            const screenBlob = new Blob(screenchunks, {type: 'video/webm'})
            const video = document.getElementById('outputvid')
            const url = URL.createObjectURL(screenBlob)
            console.log(url)
            video.src = url
        }
    }
}
